import{_ as e,o as a,c as n,ag as r}from"./chunks/framework.OsDJF_Ea.js";const d="/docs/modules/multi-band-gate.png",b=JSON.parse('{"title":"Multi-Band Gate","description":"","frontmatter":{},"headers":[],"relativePath":"modules/multi-band-gate.md","filePath":"modules/multi-band-gate.md"}'),o={name:"modules/multi-band-gate.md"};function s(i,t,h,l,u,g){return a(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="multi-band-gate" tabindex="-1">Multi-Band Gate <a class="header-anchor" href="#multi-band-gate" aria-label="Permalink to &quot;Multi-Band Gate&quot;">​</a></h1><p><strong>Category:</strong> Effects</p><p>Takes one audio signal and splits it into 4 independent trigger/gate outputs, each responding only to its own frequency band. Every band is a state-variable band-pass filter feeding its own envelope follower and threshold gate -- not a real FFT/spectral analysis, which would cost far more CPU for resolution this module doesn&#39;t need (a trigger only needs &#39;is there energy in roughly this range&#39;, not exact spectral content). Grew out of PiezoInputSCM&#39;s and NoiseGate&#39;s detector-path filtering, generalized to 4 simultaneous bands on any audio-rate source. When auto-mapped to a hardware bank, Btn1-4 select which band Pot1-3 edit (threshold/Q/cutoff) -- each band remembers its own settings when you switch away and back, same soft-takeover protection as any other banked control. The 4 button LEDs double as a live gate-activity monitor: each shows its OWN band&#39;s gate state (red = open) simultaneously, so you can see the relationship between all 4 bands at a glance while tuning, not just the one currently selected. Holding a band&#39;s button also forces that band&#39;s gate output high, letting you test whatever it&#39;s wired to before the filter is even tuned to fire on its own. Red-only, not the multi-color scheme other select-button modules use: this Porta batch has a known green/blue LED polarity defect under the buttons.</p><img src="'+d+'" alt="multi-band-gate module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>inL</strong> (audio)</td><td>Left audio to analyze.</td></tr><tr><td><strong>inR</strong> (audio)</td><td>Right audio to analyze (summed with left internally -- all 4 bands share one mono detector).</td></tr><tr><td><strong>attack_ms</strong></td><td>Shared envelope attack time across all 4 bands.</td></tr><tr><td><strong>release_ms</strong></td><td>Shared envelope release time across all 4 bands.</td></tr><tr><td><strong>band1_hz</strong></td><td>Band 1 center frequency (Hz). Default 100Hz -- low percussive/thump range.</td></tr><tr><td><strong>band1_q</strong></td><td>Band 1 filter width. Lower = wider, higher = narrower/more resonant.</td></tr><tr><td><strong>band1_threshold</strong></td><td>Band 1 gate threshold, 0-1.</td></tr><tr><td><strong>band2_hz</strong></td><td>Band 2 center frequency (Hz). Default 400Hz.</td></tr><tr><td><strong>band2_q</strong></td><td>Band 2 filter width.</td></tr><tr><td><strong>band2_threshold</strong></td><td>Band 2 gate threshold, 0-1.</td></tr><tr><td><strong>band3_hz</strong></td><td>Band 3 center frequency (Hz). Default 1500Hz.</td></tr><tr><td><strong>band3_q</strong></td><td>Band 3 filter width.</td></tr><tr><td><strong>band3_threshold</strong></td><td>Band 3 gate threshold, 0-1.</td></tr><tr><td><strong>band4_hz</strong></td><td>Band 4 center frequency (Hz). Default 6000Hz -- high/scrape/hiss range.</td></tr><tr><td><strong>band4_q</strong></td><td>Band 4 filter width.</td></tr><tr><td><strong>band4_threshold</strong></td><td>Band 4 gate threshold, 0-1.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>band1_gate</strong></td><td>Band 1 gate: 1 when that band&#39;s envelope is above threshold, 0 otherwise.</td></tr><tr><td><strong>band2_gate</strong></td><td>Band 2 gate.</td></tr><tr><td><strong>band3_gate</strong></td><td>Band 3 gate.</td></tr><tr><td><strong>band4_gate</strong></td><td>Band 4 gate.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>For a contact mic with both a low percussive thump and a higher-frequency scrape/hiss on the same signal, narrow band1 around the thump and use band1_gate to trigger -- leave band4 wide and high to catch the scrape separately if you want to use it for something else. Each gate output can drive an ADSR, a Sequencer gate input, or anything else that reads a 0/1 trigger. Unlike NoiseGate, there&#39;s no audio pass-through here -- this module is triggers only; route the same source into NoiseGate or a Filter separately if you also need shaped audio. On hardware: assign a bank, press Btn1 to edit band 1 with Pot1-3, press Btn2 for band 2, and so on -- each band&#39;s threshold/Q/Hz sticks even when you switch to editing a different band. Watch all 4 button LEDs while adjusting -- each lights up red when its own band&#39;s gate is open, so you can see all 4 bands&#39; activity at once before connecting anything downstream. Hold a band&#39;s button to manually force its gate open and test the rest of the patch independently of tuning.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const p=e(o,[["render",s]]);export{b as __pageData,p as default};
